package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bruto.BrutoTools;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.RszConstant;
import be.schaubroeck.lpb.tools.Rszppo;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.math.BigDecimal;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BRUTO_MAANDLOON_KEY;

@AllArgsConstructor
public class LoonElementVerwerker {
    private static final int SCALE = 2;

    private final ConstantManager constantManager;
    private final RszConstantService rszConstantService;

    public void verwerkTotLoonElement(
            Opper opper, LoonElementManager manager, AardKodeExtensie looncode, Money bedrag, RekenTijd rekenTijd,
            MoneyMap<AardKodeExtensie> carryoverMap) {
        verwerkTotLoonElement(opper, manager, looncode, bedrag, bedrag, rekenTijd, carryoverMap);
    }

    public void verwerkTotLoonElement(
            Opper opper, LoonElementManager manager, AardKodeExtensie looncode, Money bedrag, Money basisSi,
            RekenTijd rekenTijd, MoneyMap<AardKodeExtensie> carryoverMap) {
        basisSi = verhogingBassi(basisSi, opper, rekenTijd);
        LoonElement element = new LoonElement(looncode);
        manager.addLoonElement(element, opper);
        if (bedrag.signum() != 0) {
            bedrag = bedrag.add(carryoverMap.getMoney(looncode));
            carryoverMap.put(looncode, bedrag.subtract(bedrag.round(SCALE)));
        }
        element.putProperty(BRUTO_MAANDLOON_KEY, bedrag.round(SCALE));
        if (BrutoTools.heeftBassi(element.getAardKodeExtensie(), opper.getOpdracht().getHoedanigheid())) {
            element.putProperty(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY, basisSi.round(SCALE));
        }
    }

    public Money verhogingBassi(Money bassi, Opper opper, RekenTijd rekenTijd) {
        BigDecimal factor = getFactor(opper, rekenTijd);
        return bassi.multiply(factor).round(SCALE);
    }

    BigDecimal getFactor(Opper opper, RekenTijd rekenTijd) {
        if (isTypeBijdrage1(opper, rekenTijd)) {
            return constantManager.getActualConstant(Konstanten.KST_VERHOGING_BASSOC_TYPE_BIJDRAGE_1, rekenTijd).getProcentFactor();
        } else {
            return BigDecimal.ONE;
        }
    }

    public boolean isTypeBijdrage1(Opper opper, RekenTijd rekenTijd) {
        if (RekenTools.getTijdperk(rekenTijd) == AkeTijdperk.DMFAPPL) {
            return isBijdrage1Dmfappl(opper, rekenTijd);
        } else {
            return false;
        }
    }

    boolean isBijdrage1Dmfappl(Opper opper, RekenTijd rekenTijd) {
        Rszppo rszppo = opper.getRszppo();
        LocalDate datum = TimeTools.getZoekDatum(opper, rekenTijd.rekenPeriode);
        RszConstant rszConstant = rszConstantService
                .getByWerkgeversCategorieEnWerknemersKengetalEnDatum(rszppo.getWerkgeversCategorie(), rszppo.getWerknemersKengetal(), datum);
        return rszConstant != null && rszConstant.getType() == 1;
    }
}
